import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import API from '../../services/axios';

function AdminDashboard() {
  const [stats, setStats] = useState({ totalEvents: 0, totalBookings: 0, totalRevenue: 0 });
  const [recentBookings, setRecentBookings] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => { fetchData(); }, []);

  const fetchData = async () => {
    try {
      const [eventsRes, bookingsRes, paymentsRes] = await Promise.all([
        API.get('/events'),
        API.get('/bookings/all/bookings'),
        API.get('/payments/all/payments'),
      ]);
      setStats({
        totalEvents: eventsRes.data.count || 0,
        totalBookings: bookingsRes.data.count || 0,
        totalRevenue: paymentsRes.data.totalRevenue || 0,
      });
      setRecentBookings(bookingsRes.data.bookings?.slice(0, 5) || []);
    } catch (err) { console.error(err); }
    finally { setLoading(false); }
  };

  if (loading) return (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '100vh', background: '#fdf6f3' }}>
      <div style={{ textAlign: 'center' }}>
        <div style={{ fontSize: '2.5rem', marginBottom: '1rem' }}>🌸</div>
        <p style={{ color: '#c9a99a' }}>Loading...</p>
      </div>
    </div>
  );

  return (
    <div style={{ padding: '2rem', background: '#fdf6f3', minHeight: '100vh', fontFamily: "'DM Sans', sans-serif" }}>
      <div style={{ marginBottom: '2rem' }}>
        <h1 style={{ fontSize: '1.6rem', fontWeight: '700', color: '#2d1f1f', margin: 0, fontFamily: "'Cormorant Garamond', serif" }}>Dashboard Overview</h1>
        <p style={{ color: '#a08880', fontSize: '0.84rem', marginTop: '4px' }}>Welcome back, Admin! 🌸</p>
      </div>

      {/* Stats */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '1rem', marginBottom: '2rem' }}>
        {[
          { label: 'Total Events', value: stats.totalEvents, icon: '🎭', color: '#c9a99a', bg: '#fdeee9' },
          { label: 'Total Bookings', value: stats.totalBookings, icon: '🎫', color: '#8aad9a', bg: '#edf5f0' },
          { label: 'Total Revenue', value: `₹${stats.totalRevenue.toLocaleString()}`, icon: '💰', color: '#b8a070', bg: '#fdf5e6' },
        ].map(card => (
          <div key={card.label} style={{ background: 'white', borderRadius: '16px', padding: '1.5rem', boxShadow: '0 2px 12px rgba(201,169,154,0.1)', border: '1px solid #f5e8e3', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <div>
              <p style={{ color: '#a08880', fontSize: '0.78rem', marginBottom: '6px' }}>{card.label}</p>
              <p style={{ color: card.color, fontSize: '1.8rem', fontWeight: '800', margin: 0 }}>{card.value}</p>
            </div>
            <div style={{ background: card.bg, width: '48px', height: '48px', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1.4rem' }}>{card.icon}</div>
          </div>
        ))}
      </div>

      {/* Quick Actions */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))', gap: '1rem', marginBottom: '2rem' }}>
        {[
          { to: '/admin/create-event', icon: '➕', label: 'Create Event', color: '#c9a99a' },
          { to: '/admin/manage-events', icon: '📝', label: 'Manage Events', color: '#8aad9a' },
          { to: '/admin/bookings', icon: '📊', label: 'All Bookings', color: '#b8a070' },
        ].map(action => (
          <Link key={action.to} to={action.to} style={{
            background: 'white', borderRadius: '14px', padding: '1.2rem',
            textDecoration: 'none', boxShadow: '0 2px 12px rgba(201,169,154,0.1)',
            textAlign: 'center', transition: 'all 0.2s', border: '2px solid #f5e8e3', display: 'block'
          }}
            onMouseEnter={e => { e.currentTarget.style.borderColor = action.color; e.currentTarget.style.transform = 'translateY(-2px)'; }}
            onMouseLeave={e => { e.currentTarget.style.borderColor = '#f5e8e3'; e.currentTarget.style.transform = 'translateY(0)'; }}
          >
            <div style={{ fontSize: '2rem', marginBottom: '8px' }}>{action.icon}</div>
            <p style={{ color: action.color, fontWeight: '600', fontSize: '0.84rem', margin: 0 }}>{action.label}</p>
          </Link>
        ))}
      </div>

      {/* Recent Bookings Table */}
      <div style={{ background: 'white', borderRadius: '16px', padding: '1.5rem', boxShadow: '0 2px 12px rgba(201,169,154,0.1)', border: '1px solid #f5e8e3' }}>
        <h2 style={{ fontWeight: '700', color: '#2d1f1f', marginBottom: '1.2rem', fontFamily: "'Cormorant Garamond', serif", fontSize: '1.2rem' }}>Recent Bookings</h2>
        {recentBookings.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '2rem', color: '#c9a99a' }}>
            <div style={{ fontSize: '2rem', marginBottom: '0.5rem' }}>🌷</div>
            <p style={{ color: '#a08880' }}>No bookings yet</p>
          </div>
        ) : (
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.84rem' }}>
            <thead>
              <tr style={{ background: '#fdf6f3' }}>
                {['USER', 'EMAIL', 'EVENT', 'SEATS', 'AMOUNT', 'BOOKING STATUS'].map(h => (
                  <th key={h} style={{ padding: '10px 14px', textAlign: 'left', color: '#a08880', fontWeight: '600', fontSize: '0.72rem', letterSpacing: '0.5px' }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {recentBookings.map((b, i) => (
                <tr key={b._id} style={{ borderBottom: '1px solid #f5e8e3', background: i % 2 === 0 ? 'white' : '#fffaf8' }}>
                  <td style={{ padding: '12px 14px', fontWeight: '600', color: '#2d1f1f' }}>{b.user?.name}</td>
                  <td style={{ padding: '12px 14px', color: '#a08880' }}>{b.user?.email}</td>
                  <td style={{ padding: '12px 14px', color: '#6b5a55' }}>{b.event?.name}</td>
                  <td style={{ padding: '12px 14px', color: '#6b5a55', textAlign: 'center' }}>{b.numberOfTickets}</td>
                  <td style={{ padding: '12px 14px', fontWeight: '700', color: '#c9a99a' }}>₹{b.totalAmount}</td>
                  <td style={{ padding: '12px 14px' }}>
                    <span style={{
                      padding: '4px 12px', borderRadius: '20px', fontSize: '0.72rem', fontWeight: '600',
                      background: b.status === 'confirmed' ? '#edf5f0' : b.status === 'pending' ? '#fef9ec' : '#fdeee9',
                      color: b.status === 'confirmed' ? '#4a8a6a' : b.status === 'pending' ? '#8a7040' : '#a05040'
                    }}>{b.status}</span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}
export default AdminDashboard;
